// Reproduced: order with 20% discount shows wrong total
function calculateTotal(items: OrderItem[], discount: number): number {
  const subtotal = items.reduce((sum, item) => sum + item.price * item.qty, 0)
  const discountAmount = subtotal * discount
  return subtotal - discountAmount  // BUG: should be subtotal * (1 - discount)
}

// Fixed: use integer math for precision
function calculateTotal(items: OrderItem[], discount: number): number {
  const subtotal = items.reduce((sum, item) => sum + item.price * item.qty * 100, 0)
  const discountAmount = Math.round(subtotal * discount)
  return (subtotal - discountAmount) / 100
}

