// Hotfix: add handling fee for international
const HANDLING_FEE_CENTS = 650
function calculateShipping(order: Order): number {
  const baseCents = order.weight * 50  // $0.50 per lb in cents
  if (order.isInternational) {
    return (baseCents * 1.5 + HANDLING_FEE_CENTS) / 100
  }
  return baseCents / 100
}

