const s3 = new S3Client({ region: 'us-east-1' })
const BUCKET = 'user-avatars-prod'

async function uploadAvatar(userId: string, file: Buffer): Promise<string> {
  const resized = await sharp(file).resize(200, 200).jpeg({ quality: 80 }).toBuffer()
  const key = `avatars/${userId}/200.jpg`
  await s3.send(new PutObjectCommand({
    Bucket: BUCKET, Key: key,
    Body: resized, ContentType: 'image/jpeg'
  }))
  return `https://cdn.example.com/${key}`
}

